// We are directly after the Postgres node.
// So $json is the row returned by Load User & Chat.

const row = $json;

const phone        = row.phone;
const userText     = row.user_message;
const userName     = row.name;
const coordName    = row.coordinator_name;
const coordPhone   = row.coordinator_phone;

const prevSummary  = row.summary || null;
const prevRecent   = row.recent_messages || [];

const userContext = [];

// Add user name if available
if (userName) {
  userContext.push(`User: ${userName}`);
}

// Add conversation summary
if (prevSummary) {
  userContext.push(`Conversation Summary: ${prevSummary}`);
} else {
  userContext.push(`Status: First-time conversation`);
}

const contextString = userContext.join('\n');

// ============================================
// BUILD PROMPT STRING FOR AI NODE
// ============================================
let promptParts = [];

// Add context
promptParts.push(`CONTEXT:\n${contextString}\n`);

// Add recent conversation history
if (prevRecent && prevRecent.length > 0) {
  promptParts.push('RECENT CONVERSATION:');
  prevRecent.forEach(msg => {
    const role = msg.role.toUpperCase();
    promptParts.push(`${role}: ${msg.content}`);
  });
  promptParts.push('');  // Empty line before current message
}

// Add current user message
promptParts.push(`USER: ${userText}`);

const prompt = promptParts.join('\n');
return {
  json: {
    phone,
    userName,
    coordName,
    coordPhone,
    prevSummary,
    prevRecent,
    text: userText,
    prompt
  }
};

// ============================================
// ROBUST AI OUTPUT PARSER
// Handles multiple output formats from n8n AI Agent:
// 1. Wrapped: { output: "{json string}" }
// 2. Direct: { reply_text: "...", action: {...} }
// 3. Multiple responses: "{json1}\n{json2}" (tool execution)
// 4. Mixed types: string vs object
// ============================================

let outputObj;
let rawOutput;

// STEP 1: Extract raw output (handle wrapper or direct)
if ($json.output !== undefined) {
  rawOutput = $json.output; // Wrapped format
} else if ($json.reply_text !== undefined) {
  rawOutput = $json; // Already structured
} else {
  throw new Error(`Unexpected AI output format. Keys found: ${Object.keys($json).join(', ')}`);
}

// STEP 2: Parse if string (handle multiple JSON objects)
if (typeof rawOutput === 'string') {
  try {
    // Split by newlines, filter empty, take last valid JSON
    const lines = rawOutput
      .trim()
      .split('\n')
      .map(l => l.trim())
      .filter(l => l.length > 0);

    if (lines.length === 0) {
      throw new Error('Empty output string from AI');
    }

    // Try parsing from last to first (most recent response wins)
    let parsed = null;
    let parseErrors = [];

    for (let i = lines.length - 1; i >= 0; i--) {
      try {
        parsed = JSON.parse(lines[i]);
        if (parsed.reply_text && parsed.action) {
          outputObj = parsed; // Valid structure found
          break;
        }
      } catch (e) {
        parseErrors.push(`Line ${i + 1}: ${e.message}`);
      }
    }

    if (!outputObj) {
      throw new Error(
        `No valid JSON found in ${lines.length} lines.\n` +
        `Parse errors: ${parseErrors.join('; ')}\n` +
        `Raw output: ${rawOutput.substring(0, 500)}`
      );
    }

  } catch (e) {
    throw new Error(
      `Failed to parse AI output string.\n` +
      `Error: ${e.message}\n` +
      `Raw (first 500 chars): ${rawOutput.substring(0, 500)}`
    );
  }
} else if (typeof rawOutput === 'object' && rawOutput !== null) {
  outputObj = rawOutput; // Already an object
} else {
  throw new Error(`AI output is neither string nor object. Type: ${typeof rawOutput}`);
}

// STEP 3: Validate required structure
if (!outputObj || typeof outputObj !== 'object') {
  throw new Error(`Parsed output is not an object: ${JSON.stringify(outputObj)}`);
}

if (typeof outputObj.reply_text !== 'string') {
  throw new Error(
    `Missing or invalid 'reply_text' field. ` +
    `Expected string, got: ${typeof outputObj.reply_text}. ` +
    `Full object: ${JSON.stringify(outputObj)}`
  );
}

if (!outputObj.action || typeof outputObj.action !== 'object') {
  throw new Error(
    `Missing or invalid 'action' field. ` +
    `Expected object, got: ${typeof outputObj.action}. ` +
    `Full object: ${JSON.stringify(outputObj)}`
  );
}

// STEP 4: Validate action structure
const validTypes = ['none', 'register', 'unregister'];
const actionType = outputObj.action.type || 'none';

if (!validTypes.includes(actionType)) {
  throw new Error(
    `Invalid action.type: "${actionType}". ` +
    `Must be one of: ${validTypes.join(', ')}`
  );
}

// Warn if event_id is missing when type requires it
if ((actionType === 'register' || actionType === 'unregister') && 
    outputObj.action.event_id == null) {
  console.warn(
    `⚠️ Action type "${actionType}" but event_id is null. ` +
    `This may cause downstream errors.`
  );
}

// STEP 5: Return normalized output
return {
  json: {
    aiReply: outputObj.reply_text,
    action_type: actionType,
    event_id: outputObj.action.event_id ?? null,

    // Debug info (remove in production if not needed)
    _debug: {
      input_keys: Object.keys($json),
      had_wrapper: $json.output !== undefined,
      lines_parsed: typeof rawOutput === 'string' ? rawOutput.split('\n').length : 1,
      original_type: typeof rawOutput
    }
  }
};

// Expecting request body like:
