// Get notifications from Set node
const notifications = $items('Attach Notification Context');

// Get events from Postgres node  
const allEvents = $items('Fetch Events for hype');

// Build a map of events by ID for fast lookup
const eventMap = {};
for (const eventItem of allEvents) {
  const event = eventItem.json;
  if (!eventMap[event.id]) {
    eventMap[event.id] = event;
  }
}

// Build results array
const results = [];

for (const notifItem of notifications) {
  const notif = notifItem.json;
  const userName = notif.user_name;
  const userPhone = notif.phone;
  const notificationId = notif.notification_id;
  const eventIds = notif.event_ids;

  // Get events in the ORDER specified by event_ids (preserves randomization)
  const orderedEvents = [];
  for (const eventId of eventIds) {
    if (eventMap[eventId]) {
      orderedEvents.push(eventMap[eventId]);
    }
  }

  if (orderedEvents.length === 0) {
    continue;
  }

  // Format events for AI
  const eventDetails = orderedEvents.map(e => 
    `Event: ${e.name}\nDescription: ${e.description}`
  ).join('\n\n---\n\n');

  results.push({
    user_name: userName,
    phone: userPhone,
    notification_id: notificationId,
    event_details: eventDetails,
    event_count: orderedEvents.length
  });
}

return results.map(r => ({ json: r }));

// Get all notifications
const notifications = $items('Attach Notification Context');

// Collect all unique event IDs across all notifications
const uniqueEventIds = new Set();

for (const notifItem of notifications) {
  const eventIds = notifItem.json.event_ids;
  eventIds.forEach(id => uniqueEventIds.add(id));
}

// Convert to array
const eventIdsArray = Array.from(uniqueEventIds);

// Return as single item for Postgres to query once
return [{
  json: {
    event_ids: eventIdsArray,
    // Also pass through notifications for next step
    _notifications: notifications.map(item => item.json)
  }
}];

